import{_ as i,o,c as e,ae as a}from"./chunks/framework.RRduUuAx.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"szu/business/chapter-9.md","filePath":"szu/business/chapter-9.md"}'),t={name:"szu/business/chapter-9.md"};function u(r,l,s,c,n,d){return o(),e("div",null,[...l[0]||(l[0]=[a('<h2 id="第一节、知识管理的概念" tabindex="-1">第一节、知识管理的概念 <a class="header-anchor" href="#第一节、知识管理的概念" aria-label="Permalink to &quot;第一节、知识管理的概念&quot;">​</a></h2><ol><li>知识的概念、特点及分类 <ul><li>概念：<strong>是指经过人的思维整理过的数据、信息、形象、意象、价值标准以及社会的其他符号化产物等。</strong></li><li>特点 <ul><li>1.不可替代性。知识具有很多种类型，如自然知识，信息技术知识，每种知识都具有独立性不可替代。</li><li>2.互补性</li><li>3.不可逆性。人们一旦掌握了某种知识，便不可能被剥夺。</li><li>4.无形性</li><li>5.非稀缺性</li><li>6.非消耗性</li><li>7.可共享性</li><li>8.增值性。知识在生产、传播和使用过程中，会因更多的人使用而形成标准，并向其增添新的内容而增值。</li></ul></li><li>分类 <ul><li><strong>根据知识的性质分类</strong>。根据经合组织(OECD)的划分： <ul><li>1.事实知识。<code>知道是什么</code>知识。</li><li>2.原理知识。<code>知道为什么</code>知识。</li><li>3.技能知识。<code>知道怎么做</code>知识。</li><li>4.人力知识。<code>知道是谁</code>知识。</li></ul></li><li>根据知识的表现形式分类 <ul><li>1.显性知识，又称编码知识，即可以转化为数据呈现的知识。（Know-what、Know-why）</li><li>2.隐性知识，由称未编码知识，指难以表达和共享的知识。(Know-how、Know-who)</li></ul></li></ul></li></ul></li><li><strong>知识管理的概念</strong><ul><li>概念：是指企业通过有计划、有目的的构建企业内部知识网络进行内部学习、构建企业外部知识网络进行外部学习，有效地实现显性知识和隐性知识的互相转换，并在装换过程中创造、运用、积累和扩散知识，从而最终提高企业的学习能力、应变能力和创新能力的系统过程。</li><li>特点 <ul><li>1.知识管理的目标是通过知识的共享与创新来增加企业的价值</li><li>2.<strong>知识管理是一个螺旋循环的过程</strong>。包含几种程序： <ul><li>1.共同化</li><li>2.外化</li><li>3.联结化</li><li>4.内化</li></ul></li><li>3.知识管理是信息管理的延伸和发展</li><li>4.知识管理与人力资源管理密切相关</li><li>5.知识管理是一种全新的经营管理模式</li></ul></li></ul></li></ol><h2 id="第二节、知识管理的内容-原则及意义" tabindex="-1">第二节、知识管理的内容，原则及意义 <a class="header-anchor" href="#第二节、知识管理的内容-原则及意义" aria-label="Permalink to &quot;第二节、知识管理的内容，原则及意义&quot;">​</a></h2><ol><li><strong>知识管理的内容</strong><ul><li>1.知识的<code>采集和加工</code>。是知识管理的起点。</li><li>2.知识的存储与积累</li><li>3.知识的传播与共享</li><li>4.知识的应用与创新</li></ul></li><li><code>知识管理原则</code><ul><li>1.积累原则。知识需要积累和挖掘，积累是知识管理的基础。企业要充分利用网络，加强对网络中知识的管理，最大限度地吸纳和利用外部知识。</li><li>2.信任原则。<code>是实现知识的交流、使用和共享的前提。</code></li><li>3.交流原则。最常见的就是老员工与新员工“传帮带”</li><li>4.共享原则。将一个项目的个体行为，拓展为一个企业的整体行为。</li><li>5.创新原则</li></ul></li><li><strong>知识管理的意义</strong><ul><li>1.知识管理是适应资源环境变化的必然结果</li><li>2.知识管理的实施有助于企业的创新</li><li>3.知识管理的实施有助于提高企业的适应性</li><li>4.知识管理的实施有助于提高企业的生产效率</li></ul></li></ol><h2 id="第三节、知识管理策略" tabindex="-1">第三节、知识管理策略 <a class="header-anchor" href="#第三节、知识管理策略" aria-label="Permalink to &quot;第三节、知识管理策略&quot;">​</a></h2><ol><li>知识管理策略的类型 <ul><li><em>1.知识管理的编码策略</em><ul><li>概念：知识管理的编码策略，又叫显性策略，它是基于知识再用的知识管理策略。</li><li>特点： <ul><li>1.在知识编码策略中采用的是<code>“人到文档”方式</code></li><li>2.编码策略<code>主要依靠是“规模效应”</code></li><li>3.编码策略的<code>核心是IT系统</code></li></ul></li></ul></li><li>2.知识管理的个人化策略 <ul><li>概念：知识管理的个人化策略，又叫隐性策略，即强调通过与知识创造者的直接接触和交流实现只是学习和共享。</li><li>特点： <ul><li>1.个人化策略注重隐性知识的交流和共享</li><li>2.个人化策略<code>主要采用的是“专家”模式</code></li><li>3.个人化策略重视人员网络</li></ul></li></ul></li></ul></li><li><strong>知识管理策略的选择</strong><ul><li>1.企业知识管理策略应反映其采取的总体战略</li><li>2.知识管理策略的选择应考虑企业的发展阶段</li><li>3.知识管理策略的选择应考虑企业事业部之间的关系</li><li>4.企业知识管理策略的选择应考虑产品所处的生命周期阶段</li><li>6.知识管理策略的选择与员工所依靠的知识特性相关</li></ul></li></ol><h2 id="第四节、知识管理的实施" tabindex="-1">第四节、知识管理的实施 <a class="header-anchor" href="#第四节、知识管理的实施" aria-label="Permalink to &quot;第四节、知识管理的实施&quot;">​</a></h2><ol><li>设立知识管理部门 <ul><li><strong>知识主管的具体职责</strong><ul><li>1.审视知识资源对本企业发展的重要意义，并将其提升到一个重要层次上来。</li><li>2.负责构建公司的知识管理基础架构</li><li>3.有计划地提高企业员工的知识水平和优化其知识结构</li><li>4.股利企业员工在工作实践中进行知识的交流与共享，营造一个知识交流与共享的企业内部环境</li><li>5.监督保证知识库内容的质量、深度、风格、并保持与公司的发展相一致，以及知识库设施的正常运行与信息更新。</li></ul></li></ul></li><li>选择知识管理策略</li><li>转变观念</li><li>建立<code>知识管理的激励机制</code><ul><li>1.知识运行机制</li><li>2.知识明晰机制</li><li>3.知识绩效机制</li><li>4.知识奖惩机制</li></ul></li><li>建设知识管理的基础设施 <ul><li>知识管理信息系统由三个层次组成<code>最底层是计算机网络和知识库、第二层是计算机服务层（系统软件层）、第三层是应用软件层</code></li></ul></li><li>构建基于内部学习的企业内部知识网络</li><li>构建基于外部学习的企业外部知识网络 <ul><li>1.向战略伙伴学习</li><li>2.向竞争对手学习</li><li>3.向供应商、分销商、客户学习</li><li>4.通过资料学习</li><li>5.通过培训学习</li></ul></li><li>对企业的知识流程进行重组</li><li>将企业的知识资源融入产品或服务及其生产过程和管理过程</li><li>建设有利于知识管理的企业文化</li></ol>',8)])])}const g=i(t,[["render",u]]);export{_ as __pageData,g as default};
